<template>
<div :class="['proList',{'paddingtwo':proList.length<3}]">
    <!-- 顶部筛选 -->
<div class="nav">
  <p class="red" >{{title}}</p>
  <p :class="[{down:condition.priceOrder == 'desc'},{up:condition.priceOrder == 'asc'},{red:condition.priceOrder!=''}]" @click="orderPrice">价格    
  </p>
  <p :class="{red:condition.salesOrder!=''}" @click="orderSales">销量</p>
  <p :class="{red:condition.news!=0}" @click="getNew">新品</p>
</div>

<div class="con-list">
    <pro-list v-for="pro in proList" :key="pro.id" :pro="pro"></pro-list>
   
   </div>
    <p class="none" v-show="proList == ''">
        <img src="../assets/noCart.png" alt="">
    </p>
    </div>
</template>
<script>
import ProList from '@/components/ProList'
export default {
    props:['id'],
     components:{
    ProList
 },
    data(){
        return{
        condition:{
            page:1,
            limit:8,
            keyword:'',
            sid:31,
            news:0,
            priceOrder:'',//asc,desc
            salesOrder:''

        },
        proList:[],
        title:'全部',
       
        }
    },
    created(){
        this.condition.sid = this.id;
        this.title = this.$route.query.title;
        this.getPro();
    },
 methods:{
// 价格排序
orderPrice(){
    // 销量排序为空
    this.condition.salesOrder = '';
    if(this.condition.priceOrder == ''){
  this.condition.priceOrder = 'asc'
    }else if(this.condition.priceOrder && this.condition.priceOrder =='asc'){
    this.condition.priceOrder = 'desc';
}else{
   this.condition.priceOrder = ''
}
this.getPro();
},
// 销量排序
orderSales(){
    // 取消价格排序
    this.condition.priceOrder = '';

if(this.condition.salesOrder == ''){
  this.condition.salesOrder = 'desc'
    }else{
   this.condition.salesOrder = ''
}
this.getPro();
},
// 筛选新品
getNew(){
    this.condition.salesOrder = '';
    this.condition.priceOrder = '';
if(this.condition.news==0){
    this.condition.news = 1;
}else{
    this.condition.news = 0;
}
this.getPro();
},
//  获取数据
getPro(){
 this.axios.get("api/products",{
        params:this.condition
    }).then(d =>{
        this.proList = d.data.data
        console.log("this.proList",this.proList);
    })
     }
 }
}
</script>
<style lang="less">

.proList{
    width: 100vw;
    background-color: #fafafa;
    .nav{
        width: 100%;
        display: flex;
        justify-content: space-between;
        align-items: center;
        font-size: 14px;
        background-color: #fff;
        height: 40px;
        position: sticky;
        top: 0;
        right: 0;
        
        p{
            width: 25%;
            text-align: center;

        }
        .red{
           
                color: red;
           
        }
        // 价格降序
        .down{
            position: relative;
            &::after{
                content: '';
                width: 13px;
                height: 13px;
                background: url(../assets/down1.png)no-repeat 100% 100%;
                position: absolute;
                top: 5px;
                right:15px;
            }
        }
        // 价格升序
        .up{
            position: relative;
            &::after{
                content: '';
                width: 13px;
                height: 13px;
                background: url(../assets/up1.png)no-repeat 100% 100%;
                position: absolute;
                top: 5px;
                right:15px;
            }
        }
    }
.con-list{
    
    display: flex;
    justify-content: space-between;
    flex-wrap: wrap;
    padding: 0 5px ;
    div{
        width: 49%;
        margin: 5px 0;
        div{
            width: 100%;
        }
    }
}
.none{
    width: 100%;
   img{
       display: block;
       width: 80%;
       margin: 0 auto;
   }
}
}
.paddingtwo{
    padding-bottom: 300px;  
}

</style>